# Wrong: brittle exact match
def bad_metric(example, prediction, trace=None) -> bool:
    return example.answer == prediction.answer  # fails on "Paris" vs "Paris, France"

# Better: case-insensitive substring containment
def good_metric(example, prediction, trace=None) -> bool:
    return (
        example.answer.lower() in prediction.answer.lower()
        or prediction.answer.lower() in example.answer.lower()
    )
